(function(){"use strict";const r=()=>{const c=document.querySelector(".customMenuOptions"),h=document.querySelector('.mainDrawer-scrollContainer > a[href="#/home"]'),s=document.querySelector(".mainDrawer-scrollContainer");if(c){if(!c.querySelector(".sidebarHeader")){const d=document.createElement("h3");d.className="sidebarHeader";d.textContent="General";c.appendChild(d)}if(h)c.appendChild(h)}if(s&&!document.querySelector(".btnCloseMenuContainer")){const x=document.createElement("div");x.className="btnCloseMenuContainer";x.style.display="flex";x.style.justifyContent="flex-end";x.style.padding="8px 16px 0 0";const b=document.createElement("button");b.type="button";b.setAttribute("is","paper-icon-button-light");b.className="headerButton mainDrawerButton barsMenuButton headerButtonLeft paper-icon-button-light btnCloseMenu";b.title="Close Menu";b.innerHTML='<span class="material-icons" aria-hidden="true">close</span>';b.addEventListener("click",e=>{e.preventDefault();e.stopPropagation();const p=document.querySelector(".mainDrawer-backdrop, .drawer-backdrop");if(p){p.click();return}const t=document.querySelector(".btnApplicationMenu, .btnHeaderMenu, .mainDrawerButton:not(.btnCloseMenu)");if(t)t.click()});x.appendChild(b);s.insertBefore(x,s.firstChild)}};r();const o=new MutationObserver(m=>{for(let i=0;i<m.length;i++){const a=m[i].addedNodes;for(let j=0;j<a.length;j++){const n=a[j];if(n.nodeType===1){if(n.classList.contains("mainDrawer-scrollContainer")||n.classList.contains("customMenuOptions")||n.querySelector(".customMenuOptions")){r();return}}}}});o.observe(document.body,{childList:!0,subtree:!0})})();
